#include <bits/stdc++.h>
using namespace std;

const int N = 1e4 + 5;
const long long INF = 1e18;

long long dis[N];
int n, m, f[N];
long long b;
bool vis[N];

struct Edge {
    int v;
    long long w;
};

vector<Edge> e[N];

bool Dijkstra(int s, int k) {
    if (f[s] > k || f[n] > k) return false;

    memset(vis, 0, sizeof(vis));
    fill(dis + 1, dis + n + 1, INF);
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<pair<long long, int>>> q;

    dis[s] = 0;
    q.push({0, s});

    while (!q.empty()) {
        auto [d, u] = q.top();
        q.pop();

        if (vis[u]) continue;
        vis[u] = true;

        for (auto [v, w] : e[u]) {
            if (f[v] > k) continue;
            if (d + w < dis[v]) {
                dis[v] = d + w;
                q.push({dis[v], v});
            }
        }
    }

    return dis[n] <= b && dis[n] != INF;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    cin >> n >> m >> b;
    int max_f = 0;
    for (int i = 1; i <= n; i++) {
        cin >> f[i];
        max_f = max(max_f, f[i]);
    }
    for (int i = 1; i <= m; i++) {
        int u, v;
        long long w;
        cin >> u >> v >> w;
        e[u].push_back({v, w});
        e[v].push_back({u, w});
    }

    int l = -1, r = max_f + 1;
    while (l + 1 < r) {
        int mid = (l + r) / 2;
        if (Dijkstra(1, mid)) {
            r = mid;
        } else {
            l = mid;
        }
    }

    if (r > max_f) {
        cout << "AFK" << endl;
    } else {
        cout << r << endl;
    }

    return 0;
}
